INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-06060', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「全世界，都有小孩做『大事』的例子。這些孩子都不是天縱英明、出身優渥或從 小刻意栽培。根據研究，一開始他們多是『普通的孩子』，從一個很微小的動機和 行動出發。」本篇文字的標題設計為□＋□＝□的形式，請選出最合適的選項：', '["天縱英明＋刻意栽培＝做大事的小孩", "微小動機＋天縱英明＝做大事的小孩", "普通小孩＋微小的動機＝做大事的小孩", "普通小孩＋做大事的小孩＝全世界的小孩"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "97ccad9eea1c", "answer_pdf_sha1": "6128e0e82a63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06061', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '你和一位土著被困在非洲叢林，既無食物，也無水喝，於是你將把這位土著當作 「天才」，因為他懂得各種求生的技巧。相反地，如果把他帶到辦公室，要他使用 電腦，那麼情況將會完全不同，你可能會認為他是「白癡」。 閱讀上文後，請判斷下列選項何者錯誤？', '["一個人最大的勝利就是戰勝自己", "你眼中的蠢材，很可能也只是放錯地方的人才", "選對舞台，走出自己的路，就可能被視為天才", "任何人或物，只要放對了地方，都會成為有用的「可造之材」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "97ccad9eea1c", "answer_pdf_sha1": "6128e0e82a63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06062', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '當百年森林一夕之間被山鼠囓盡，成群野鳥在網罟懸翅；溪川服食過量之七彩毒液， 大批游魚在河床曝屍。那千里御風而來的春婦，蓬首垢面於島嶼上空痛哭：「福爾 摩沙！你遺棄我！福爾摩沙！何以故？」 遂降於山顛谷腹。紅檜斬首後，血流成河漫過她的足踝；折翅的蝶體在礫谷上堆積 成塚，任螻蟻搬運屍臭。遠方小鎮升起濃煙，百萬隻串烤鵪鶉清燉嫩鴿，滿足人們 對和平的慾望。煙塵瀰漫天空，令群花褪色，樹蟬自動割喉。 請問春婦何以在島嶼上痛哭：「福爾摩沙！你遺棄我！」？', '["因為福爾摩沙的自然環境嚴重受損", "因為全球暖化而導致春季時數縮短", "因為福爾摩沙的治安已經日漸敗壞", "因為外來物種在福爾摩沙過度繁殖"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "97ccad9eea1c", "answer_pdf_sha1": "6128e0e82a63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06063', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '我們是一種「信」的民族，我們「信」祖宗、「信」國家、「信」領袖、「信」 主義。當我們「信」的時候，就愛之欲其生，由於「信」得太多而變成「輕信」， 於是遂擅於今天「信」這個，明天「信」那個的，總是忙著找可以一勞永逸的「最 後的答案」。我們不知道我們的不幸來源裡有一大半其實源於我們自己的「輕信」。 當我們在「輕信」的時候，會替錯誤強辯，會睜眼講瞎話，惡就是這樣被鼓勵出來的。 我們「信」得太過火，最重要的原因或許就在於我們的基因深處，有著一種害怕與 別人不同的恐懼。 依作者論述，下列各選項何者錯誤？', '["我們是相信祖宗、國家、領袖、主義的民族", "輕信的弊端就是惡之欲其死，打壓不同意見的人", "輕信來自於人類害怕被孤立，因而從眾的心理效應", "因為願意相信的對象太多，遂養成「輕信」的民族特性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "97ccad9eea1c", "answer_pdf_sha1": "6128e0e82a63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06064', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列選項，何者強調為官者應為其職務負責的態度？', '["不在其位，不謀其政", "有亂君，無亂國。有治人，無治法", "其人存，則其政舉；其人亡，則其政息", "有官守者，不得其職則去；有言責者，不得其言則去"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "97ccad9eea1c", "answer_pdf_sha1": "6128e0e82a63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06065', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '《顏氏家訓．慕賢》：「人在少年，神氣未定，所與款狎，熏漬陶染，言笑舉動， 無心於學，潛移暗化，自然似之。」下列何者較貼近上文文意？', '["白沙在涅，與之俱黑", "攀附權貴，人之常情", "血氣方剛，戒之在鬥", "朝聞夕改，與時俱進"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "97ccad9eea1c", "answer_pdf_sha1": "6128e0e82a63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06066', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列關於《孫子兵法》的選項，何者與強調「計謀」、「計算」無關？', '["攻其無備，出其不意", "兵者，詭道也。故能而示之不能，用而示之不用，近而示之遠，遠而示之近", "主孰有道？將孰有能？天地孰得？法令孰行？兵眾孰強？士卒孰練？賞罰孰明？ 吾以此知勝負矣", "激水之疾，至於漂石者，勢也；鷙鳥之擊，至於毀折者，節也。是故善戰者， 其勢險，其節短。勢如彍弩，節如發機"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "97ccad9eea1c", "answer_pdf_sha1": "6128e0e82a63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06067', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '余未成年時，喜寫字。祖母嘗太息曰：「汝好學，惜來時走錯了人家。俗話云： 『三日風，四日雨，那見文章鍋裡煮。明朝無米，吾兒奈何！』」後十五年，余嘗 得寫真潤金買柴米。祖母又曰：「那知今日鍋裡煮吾兒之畫也。」 這是齊白石追述他祖母對他說過的話語，請問他祖母對他致力於書畫一事的態度為：', '["憂心文章藝術不能作為謀生的事業", "責備他不識時務，將來必然無法養家活口", "感慨他雅好文藝，作品卻被富人放進鍋中煮毀", "勉勵他應共體風雨飄搖之歲月，即時工作以改善家庭經濟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "97ccad9eea1c", "answer_pdf_sha1": "6128e0e82a63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06068', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「蓋物之散者多漫，而聚者常斂。照乘粒珠耳，而燭物更遠，予取其遠而已；匕首 寸鐵耳，而刺人尤透，予取其透而已。大獅搏象用全力，搏兔亦用全力，小不可忽 也。粵西有修蛇，蜈蚣能制之，短不可輕也。」根據本文，作者最強調的是：', '["優勢的運用", "堅定的自信", "積極的行動", "豐富的資源"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "97ccad9eea1c", "answer_pdf_sha1": "6128e0e82a63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06069', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '坐井觀天，曰天小者，非天小也，其所見小也。夏蟲不可與語冰，非無冰也，以其 未見冰也。淺隘之子，蟄居鄉曲，見聞有限，遇事好以臆度，中者十一，不中者十 八九，皆坐井觀天、夏蟲語冰類也。依據文意，如欲獲得真知灼見，最重要的作為是：', '["覽天下之群經", "游天下之大觀", "求天下之名師", "交天下之良友"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "97ccad9eea1c", "answer_pdf_sha1": "6128e0e82a63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
